head.b:skin:
/* ============================================================
   قالب بلوجر احترافي | مصمم متاجر سلة و زد ورمز
   Ali Ahmed - salla1zid
   تصميم حصري ومبتكر - جميع الحقوق محفوظة
   ============================================================ */

/* ===== CSS Variables & Theme System ===== */
:root {
  /* Primary Colors - Enhanced */
  --primary: #6366f1;
  --primary-dark: #4f46e5;
  --primary-light: #818cf8;
  --primary-gradient: linear-gradient(135deg, #6366f1 0%, #818cf8 50%, #a78bfa 100%);
  --secondary: #8b5cf6;
  --secondary-gradient: linear-gradient(135deg, #8b5cf6 0%, #a78bfa 100%);
  --accent: #06b6d4;
  --accent-gradient: linear-gradient(135deg, #06b6d4 0%, #0891b2 100%);
  --success: #22c55e;
  --warning: #f59e0b;
  --danger: #ef4444;

  /* Text Colors */
  --text: #1e293b;
  --text-light: #64748b;
  --text-muted: #94a3b8;
  --bg: #ffffff;
  --bg-alt: #f8fafc;
  --card-bg: #ffffff;
  --border: #e2e8f0;
  --primary-rgb: 99, 102, 241;
  --secondary-purple: #8b5cf6;
  --radius: 12px;
  --radius-lg: 20px;
  --radius-full: 50px;
  --shadow: 0 4px 20px rgba(94, 59, 238, 0.1);
  --shadow-hover: 0 12px 40px rgba(94, 59, 238, 0.2);
  --transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  --ease-out-quart: cubic-bezier(0.25, 1, 0.5, 1);
  --ease-out-quint: cubic-bezier(0.22, 1, 0.36, 1);
  --ease-out-expo: cubic-bezier(0.16, 1, 0.3, 1);
  --shadow: 0 4px 25px rgba(99, 102, 241, 0.12);
  --shadow-hover: 0 15px 50px rgba(99, 102, 241, 0.25);
  --transition: all 0.35s cubic-bezier(0.4, 0, 0.2, 1);
  --ease-out-quart: cubic-bezier(0.25, 1, 0.5, 1);
  --ease-out-quint: cubic-bezier(0.22, 1, 0.36, 1);
  --ease-out-expo: cubic-bezier(0.16, 1, 0.3, 1);
  --ease-back: cubic-bezier(0.34, 1.56, 0.64, 1);
  --header-bg: rgba(65, 47, 144, 0.25);

[data-theme="dark"] {
  --primary: #818cf8;
  --primary-light: #a78bfa;
  --primary-gradient: linear-gradient(135deg, #818cf8 0%, #a78bfa 100%);
  --secondary: #c4b5fd;
  --secondary-gradient: linear-gradient(135deg, #a78bfa 0%, #ddd6fe 100%);
  --accent: #22d3ee;
  --text: #f1f5f9;
  --text-light: #cbd5e1;
  --text-muted: #94a3b8;
  --bg: #0f172a;
  --bg-alt: #1e293b;
  --card-bg: #1e293b;
  --border: #334155;
  --primary-rgb: 129, 140, 248;
  --secondary-purple: #c4b5fd;
  --shadow: 0 4px 25px rgba(129, 140, 248, 0.15);
  --shadow-hover: 0 12px 50px rgba(129, 140, 248, 0.25);
  --header-bg: rgba(15, 23, 42, 0.95);
}

/* ===== Base ===== */
* { margin: 0; padding: 0; box-sizing: border-box; }
html { scroll-behavior: smooth; }
body {
  font-family: 'Tajawal', sans-serif !important;
  line-height: 1.6;
  color: var(--text);
  background: var(--bg);
  direction: rtl;
  text-align: right;
  overflow-x: hidden;
  transition: background 0.3s ease, color 0.3s ease;
}
a { text-decoration: none; color: var(--primary); transition: var(--transition); }
a:hover { color: var(--secondary); }
ul { list-style: none; }
img { max-width: 100%; height: auto; }
.container {
  width: 100%;
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 20px;
}
::selection { background: var(--primary); color: white; }

/* ===== Scrollbar ===== */
::-webkit-scrollbar { width: 10px; }
::-webkit-scrollbar-track { background: var(--bg-alt); }
::-webkit-scrollbar-thumb { background: var(--primary-gradient); border-radius: 5px; }

/* ===== Header ===== */
.header {
  position: fixed;
  top: 20px;
  left: 50%;
  transform: translateX(-50%);
  width: 90%;
  max-width: 1200px;
  z-index: 1000;
  padding: 12px 25px;
  border-radius: 60px;
}
.header::before {
  content: '';
  position: absolute;
  inset: 0;
  background: var(--header-bg);
  backdrop-filter: blur(25px);
  -webkit-backdrop-filter: blur(25px);
  border-radius: 60px;
  z-index: -1;
  border: 1px solid rgba(255,255,255,0.1);
}
.header::after {
  content: '';
  position: absolute;
  inset: 0;
  border-radius: 60px;
  padding: 1px;
  background: linear-gradient(135deg, rgba(255,255,255,0.15), rgba(255,255,255,0.05));
  pointer-events: none;
  z-index: -2;
}
.header.scrolled { 
  top: 12px; 
  padding: 10px 22px;
  box-shadow: 0 8px 35px rgba(0,0,0,0.15);
}
.header-content {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 25px;
}
.logo a {
  font-size: 1.6rem;
  font-weight: 800;
  background: var(--primary-gradient);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  letter-spacing: -0.5px;
  transition: var(--transition);
}
.logo a:hover {
  filter: drop-shadow(0 0 10px rgba(99,102,241,0.3));
}
[data-theme="light"] .logo a { 
  color: var(--primary);
}
.nav-links { 
  display: flex; 
  gap: 10px;
}
.nav-links li a {
  color: white;
  font-weight: 600;
  padding: 10px 18px;
  border-radius: 50px;
  font-size: 0.92rem;
  transition: var(--transition);
  position: relative;
  display: flex;
  align-items: center;
  gap: 6px;
}
.nav-links li a::before {
  content: '';
  position: absolute;
  inset: 0;
  background: rgba(255,255,255,0.05);
  border-radius: 50px;
  z-index: -1;
  transform: scaleX(0);
  transform-origin: left;
  transition: transform 0.4s var(--ease-out-quart);
}
.nav-links li a:hover,
.nav-links li a.active {
  background: rgba(255,255,255,0.15);
  color: white;
  transform: translateY(-2px);
}
.nav-links li a:hover::before,
.nav-links li a.active::before {
  transform: scaleX(1);
}
[data-theme="light"] .nav-links li a { 
  color: #475569;
}
[data-theme="light"] .nav-links li a:hover,
[data-theme="light"] .nav-links li a.active {
  background: var(--primary-gradient);
  color: white;
}
.header-actions { 
  display: flex; 
  align-items: center; 
  gap: 14px;
}
.theme-toggle {
  width: 40px; height: 40px;
  border-radius: 50%;
  background: rgba(255,255,255,0.1);
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: var(--transition);
  border: none;
  font-size: 1.2rem;
  color: white;
  position: relative;
  overflow: hidden;
}
.theme-toggle::before {
  content: '';
  position: absolute;
  inset: 0;
  background: rgba(255,255,255,0.15);
  border-radius: 50%;
  transform: scale(0);
  transition: transform 0.4s var(--ease-back);
}
.theme-toggle:hover { 
  transform: scale(1.1);
}
.theme-toggle:hover::before {
  transform: scale(1);
}
[data-theme="light"] .theme-toggle { 
  color: #333;
  background: rgba(0,0,0,0.05);
}
.mobile-toggle {
  display: none;
  width: 40px; height: 40px;
  border-radius: 50%;
  background: rgba(255,255,255,0.1);
  cursor: pointer;
  align-items: center;
  justify-content: center;
  border: none;
  font-size: 1.3rem;
  color: white;
  transition: var(--transition);
}
.mobile-toggle:hover {
  transform: scale(1.1);
}
[data-theme="light"] .mobile-toggle { 
  color: #333;
  background: rgba(0,0,0,0.05);
}
.header-whatsapp-btn {
  display: flex;
  align-items: center;
  gap: 8px;
  background: linear-gradient(135deg, #25D366 0%, #128C7E 100%);
  color: white !important;
  padding: 10px 20px;
  border-radius: 50px;
  font-weight: 700;
  font-size: 0.9rem;
  transition: var(--transition);
  box-shadow: 0 4px 15px rgba(37,211,102,0.3);
  text-decoration: none;
  border: none;
  cursor: pointer;
}
.header-whatsapp-btn:hover { 
  transform: translateY(-3px);
  box-shadow: 0 8px 25px rgba(37,211,102,0.5);
  color: white;
}
.header-whatsapp-btn:active {
  transform: translateY(-1px);
}

/* ===== Mobile Menu ===== */
@media (max-width: 992px) {
  .nav {
    position: fixed;
    top: 0; right: -100%;
    width: 280px; max-width: 85%;
    height: 100vh;
    background: linear-gradient(135deg, rgba(65,47,144,0.98), rgba(138,125,219,0.95));
    backdrop-filter: blur(20px);
    box-shadow: -10px 0 40px rgba(0,0,0,0.4);
    transition: right 0.4s cubic-bezier(0.4,0,0.2,1);
    padding: 100px 30px 40px;
    z-index: 999;
    overflow-y: auto;
  }
  .nav.active { right: 0; }
  .nav-links { flex-direction: column; gap: 5px; }
  .nav-links li a { display: block; padding: 14px 20px; border-radius: 12px; font-size: 1rem; }
  .mobile-toggle { display: flex !important; }
  .header { width: 95%; padding: 8px 15px; }
  .header-whatsapp-btn span { display: none; }
}

/* ===== Focus & Accessibility ===== */
*:focus-visible {
  outline: 2px solid var(--primary);
  outline-offset: 2px;
  border-radius: 4px;
}
button:focus-visible, a:focus-visible { outline-offset: 3px; }

/* ===== Card Hover Refinements ===== */
.service-card, .help-card, .discount-card, .store-link-card, .blog-post-card {
  transition: transform 0.4s var(--ease-out-quart), box-shadow 0.4s var(--ease-out-quart), border-color 0.3s ease;
}
.service-card:hover, .help-card:hover {
  transform: translateY(-6px);
  box-shadow: var(--shadow-hover);
}

/* ===== Section Title Polish ===== */
.section-title {
  text-align: center;
  margin-bottom: 50px;
  position: relative;
}
.section-title h2 {
  font-size: 2.2rem;
  font-weight: 800;
  color: var(--text);
  margin-bottom: 12px;
  position: relative;
  display: inline-block;
}
.section-title h2::after {
  content: '';
  display: block;
  width: 60px;
  height: 4px;
  background: var(--primary-gradient);
  border-radius: 2px;
  margin: 12px auto 0;
}
.section-title p {
  color: var(--text-light);
  font-size: 1.05rem;
  max-width: 600px;
  margin: 0 auto;
  line-height: 1.7;
}

/* ===== Hero Section ===== */
.hero-section {
  position: relative;
  min-height: 90vh;
  display: flex;
  align-items: center;
  justify-content: center;
  text-align: center;
  overflow: hidden;
  background: linear-gradient(135deg, #0f172a 0%, #1e293b 40%, #334155 100%);
  padding: 120px 0 60px;
  isolation: isolate;
}
[data-theme="light"] .hero-section { 
  background: linear-gradient(135deg, #f0f4f8 0%, #e2e9f3 40%, #ddd6fe 100%);
}
.hero-particles {
  position: absolute;
  inset: 0;
  overflow: hidden;
  pointer-events: none;
  z-index: 1;
}
.hero-particle {
  position: absolute;
  border-radius: 50%;
  opacity: 0;
  animation: floatParticle cubic-bezier(0.25, 1, 0.5, 1) forwards;
  will-change: transform, opacity;
}
.hero-particle:nth-child(1) { width: 8px; height: 8px; left: 10%; top: 20%; background: rgba(99,102,241,0.4); animation-duration: 25s; animation-delay: 0s; }
.hero-particle:nth-child(2) { width: 12px; height: 12px; left: 80%; top: 10%; background: rgba(139,92,246,0.3); animation-duration: 30s; animation-delay: 5s; }
.hero-particle:nth-child(3) { width: 6px; height: 6px; left: 50%; top: 60%; background: rgba(167,139,250,0.2); animation-duration: 28s; animation-delay: 10s; }
.hero-particle:nth-child(4) { width: 10px; height: 10px; left: 20%; top: 80%; background: rgba(99,102,241,0.25); animation-duration: 32s; animation-delay: 15s; }
@keyframes floatParticle {
  0% { 
    transform: translateY(0) translateX(0) scale(1);
    opacity: 0;
  }
  5% { 
    opacity: 0.8;
  }
  95% { 
    opacity: 0.3;
  }
  100% { 
    transform: translateY(-100vh) translateX(150px) scale(0.5);
    opacity: 0;
  }
}
.hero-content { 
  max-width: 850px; 
  position: relative; 
  z-index: 2;
  animation: heroContentSlideUp 0.8s var(--ease-out-expo) backwards;
}
@keyframes heroContentSlideUp {
  from {
    opacity: 0;
    transform: translateY(50px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}
.hero-badge {
  display: inline-block;
  background: rgba(99,102,241,0.1);
  color: rgba(99,102,241,1);
  padding: 12px 28px;
  border-radius: 50px;
  font-size: 0.95rem;
  margin-bottom: 25px;
  backdrop-filter: blur(10px);
  animation: fadeInUp 0.7s var(--ease-out-quint) backwards;
  animation-delay: 0.1s;
  border: 1px solid rgba(99,102,241,0.3);
  font-weight: 600;
  letter-spacing: 0.5px;
}
[data-theme="light"] .hero-badge { 
  background: rgba(99,102,241,0.12);
  color: #4f46e5;
  border-color: rgba(99,102,241,0.4);
}
[data-theme="dark"] .hero-badge {
  background: rgba(129,140,248,0.15);
  color: #a78bfa;
  border-color: rgba(129,140,248,0.3);
}
.hero-content h1 {
  font-size: 3.8rem;
  font-weight: 800;
  line-height: 1.15;
  margin-bottom: 25px;
  animation: fadeInUp 0.8s var(--ease-out-quint) backwards;
  animation-delay: 0.2s;
  letter-spacing: -1px;
}
[data-theme="light"] .hero-content h1 {
  background: linear-gradient(135deg, #1e293b 0%, #4f46e5 50%, #6366f1 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}
[data-theme="dark"] .hero-content h1 {
  background: linear-gradient(135deg, #f1f5f9 0%, #c4b5fd 50%, #a78bfa 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}
.hero-content > p {
  font-size: 1.25rem;
  line-height: 1.8;
  margin-bottom: 35px;
  max-width: 650px;
  margin-left: auto;
  margin-right: auto;
  animation: fadeInUp 0.8s var(--ease-out-quint) backwards;
  animation-delay: 0.3s;
  font-weight: 500;
}
[data-theme="light"] .hero-content > p { 
  color: #475569;
}
[data-theme="dark"] .hero-content > p { 
  color: #cbd5e1;
}
.hero-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 12px;
  background: var(--primary-gradient);
  color: white;
  padding: 18px 42px;
  border-radius: 60px;
  font-weight: 700;
  font-size: 1.1rem;
  transition: var(--transition);
  border: none;
  cursor: pointer;
  box-shadow: 0 8px 25px rgba(99,102,241,0.35);
  animation: fadeInUp 0.9s var(--ease-out-quint) backwards;
  animation-delay: 0.4s;
  position: relative;
  overflow: hidden;
  text-decoration: none;
}
.hero-btn::before {
  content: '';
  position: absolute;
  top: 0;
  left: -100%;
  width: 100%;
  height: 100%;
  background: rgba(255,255,255,0.2);
  transition: left 0.5s var(--ease-out-quart);
  z-index: -1;
}
.hero-btn:hover {
  transform: translateY(-4px);
  box-shadow: 0 12px 35px rgba(99,102,241,0.5);
  color: white;
}
.hero-btn:hover::before {
  left: 100%;
}
.hero-btn:active {
  transform: translateY(-2px);
}
.hero-btn i, .hero-btn svg {
  width: 20px;
  height: 20px;
  transition: var(--transition);
}
.hero-btn:hover i, .hero-btn:hover svg {
  transform: translateX(4px);
}

/* ===== Animations ===== */
@keyframes fadeInUp {
  from { opacity: 0; transform: translateY(30px); }
  to { opacity: 1; transform: translateY(0); }
}
@keyframes slideUp {
  to { opacity: 1; transform: translateY(0); }
}

/* ===== Section Common ===== */
.section { padding: 80px 0; }
.section-title { text-align: center; margin-bottom: 50px; }
.section-title h2 {
  font-size: 2.5rem;
  font-weight: 800;
  background: var(--primary-gradient);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  margin-bottom: 15px;
}
.section-title p { color: var(--text-light); max-width: 600px; margin: 0 auto; font-size: 1.1rem; }

/* ===== Services ===== */
.services-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
  gap: 35px;
  margin-top: 50px;
}
.service-card {
  background: var(--card-bg);
  border-radius: 24px;
  padding: 45px 35px;
  text-align: center;
  position: relative;
  overflow: hidden;
  box-shadow: var(--shadow);
  transition: var(--transition);
  border: 1px solid var(--border);
  isolation: isolate;
}
.service-card::before {
  content: '';
  position: absolute;
  top: 0; left: -100%;
  right: 0; height: 3px;
  background: var(--primary-gradient);
  transition: left 0.5s var(--ease-out-quart);
}
.service-card::after {
  content: '';
  position: absolute;
  inset: 0;
  background: linear-gradient(135deg, rgba(99,102,241,0.05) 0%, transparent 100%);
  opacity: 0;
  transition: opacity 0.3s ease;
  pointer-events: none;
}
.service-card:hover {
  transform: translateY(-12px);
  box-shadow: var(--shadow-hover);
  border-color: var(--primary);
}
.service-card:hover::before {
  left: 0;
}
.service-card:hover::after {
  opacity: 1;
}
.service-icon {
  width: 80px; height: 80px;
  margin: 0 auto 25px;
  border-radius: 20px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 2rem;
  background: linear-gradient(135deg, rgba(99,102,241,0.15), rgba(139,92,246,0.1));
  color: var(--primary);
  box-shadow: 0 8px 20px rgba(99,102,241,0.15);
  transition: var(--transition);
  position: relative;
  z-index: 1;
}
.service-card:hover .service-icon { 
  transform: scale(1.15) rotate(-8deg);
  background: var(--primary-gradient);
  color: white;
  box-shadow: 0 12px 30px rgba(99,102,241,0.3);
}
.service-card h3 { 
  font-size: 1.35rem; 
  color: var(--text);
  margin-bottom: 15px; 
  font-weight: 700;
  letter-spacing: -0.5px;
}
.service-card p { 
  color: var(--text-light); 
  font-size: 0.98rem; 
  line-height: 1.8;
  margin-bottom: 20px;
}
.service-features { text-align: right; margin: 20px 0; padding: 0; }
.service-features li {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 8px 0;
  font-size: 0.9rem;
  color: var(--text);
  border-bottom: 1px solid var(--border);
}
.service-features li:last-child { border-bottom: none; }

/* ===== Stats ===== */
.stats-section {
  padding: 100px 0;
  background: var(--bg-alt);
  position: relative;
  overflow: hidden;
}
.stats-section::before {
  content: '';
  position: absolute;
  top: -50%;
  right: -10%;
  width: 600px;
  height: 600px;
  border-radius: 50%;
  background: radial-gradient(circle, rgba(99,102,241,0.08) 0%, transparent 70%);
  pointer-events: none;
  z-index: 0;
}
.stats-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
  gap: 35px;
  position: relative;
  z-index: 1;
}
.stat-item {
  background: var(--card-bg);
  border-radius: 24px;
  padding: 40px 30px;
  text-align: center;
  box-shadow: var(--shadow);
  transition: var(--transition);
  border: 1px solid var(--border);
  animation: slideUp 0.7s var(--ease-out-expo) forwards;
  opacity: 0;
  transform: translateY(40px);
}
.stat-item:nth-child(1) { animation-delay: 0.1s; }
.stat-item:nth-child(2) { animation-delay: 0.2s; }
.stat-item:nth-child(3) { animation-delay: 0.3s; }
.stat-item:nth-child(4) { animation-delay: 0.4s; }
.stat-item:hover { 
  transform: translateY(-15px);
  box-shadow: var(--shadow-hover);
  border-color: var(--primary);
}
.stat-icon {
  width: 75px; height: 75px;
  margin: 0 auto 20px;
  border-radius: 20px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 2rem;
  background: linear-gradient(135deg, rgba(99,102,241,0.15), rgba(139,92,246,0.1));
  color: var(--primary);
  transition: var(--transition);
}
.stat-item:hover .stat-icon { 
  transform: scale(1.2);
  background: var(--primary-gradient);
  color: white;
  box-shadow: 0 12px 30px rgba(99,102,241,0.3);
}
.stat-number {
  font-size: 3.2rem;
  font-weight: 800;
  background: var(--primary-gradient);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  margin-bottom: 10px;
  line-height: 1.1;
}
.stat-label { 
  font-size: 1.05rem; 
  color: var(--text-light); 
  font-weight: 600;
  letter-spacing: 0.3px;
}

/* ===== About ===== */
.about-section-centered {
  padding: 80px 0;
  background: var(--bg);
  position: relative;
}
.about-content-centered {
  max-width: 750px;
  margin: 0 auto;
  text-align: center;
  padding: 40px;
  background: var(--card-bg);
  border-radius: 20px;
  box-shadow: var(--shadow);
}
.about-icon-centered {
  width: 75px; height: 75px;
  margin: 0 auto 20px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 2rem;
  background: var(--primary-gradient);
  color: white;
  box-shadow: 0 10px 20px rgba(var(--primary-rgb), 0.3);
}
.about-content-centered h2 {
  font-size: 2.2rem;
  margin-bottom: 15px;
  color: var(--primary);
}
.about-content-centered p { font-size: 1.05rem; line-height: 1.8; color: var(--text); max-width: 600px; margin: 0 auto; }
.about-actions-centered { display: flex; justify-content: center; gap: 15px; margin-top: 25px; }

/* ===== Buttons ===== */
.btn, .btn-primary-glow {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
  padding: 16px 36px;
  border-radius: 60px;
  font-weight: 700;
  font-size: 1rem;
  transition: var(--transition);
  border: none;
  cursor: pointer;
  text-decoration: none;
  background: var(--primary-gradient);
  color: white;
  box-shadow: 0 8px 25px rgba(99,102,241,0.35);
  position: relative;
  overflow: hidden;
}
.btn::before, .btn-primary-glow::before {
  content: '';
  position: absolute;
  top: 50%;
  left: 50%;
  width: 0;
  height: 0;
  border-radius: 50%;
  background: rgba(255,255,255,0.3);
  transform: translate(-50%, -50%);
  transition: width 0.6s, height 0.6s;
  pointer-events: none;
}
.btn:hover, .btn-primary-glow:hover {
  transform: translateY(-4px);
  box-shadow: 0 12px 40px rgba(99,102,241,0.45);
  color: white;
}
.btn:hover::before, .btn-primary-glow:hover::before {
  width: 300px;
  height: 300px;
}
.btn-outline-glow {
  background: transparent;
  color: var(--primary);
  border: 2px solid var(--primary);
  padding: 14px 34px;
  border-radius: 60px;
  font-weight: 700;
  font-size: 1rem;
  transition: var(--transition);
  text-decoration: none;
  display: inline-flex;
  align-items: center;
  gap: 10px;
  position: relative;
  overflow: hidden;
}
.btn-outline-glow::before {
  content: '';
  position: absolute;
  top: 0;
  left: -100%;
  width: 100%;
  height: 100%;
  background: var(--primary-gradient);
  transition: left 0.4s var(--ease-out-quart);
  z-index: -1;
}
.btn-outline-glow:hover {
  background: var(--primary-gradient);
  color: white;
  border-color: transparent;
  transform: translateY(-3px);
  box-shadow: 0 8px 25px rgba(99,102,241,0.35);
}

/* ===== Testimonials ===== */
.testimonials-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(320px, 1fr));
  gap: 35px;
  margin-top: 50px;
}
.testimonial-card {
  background: var(--card-bg);
  border-radius: 24px;
  padding: 35px;
  box-shadow: var(--shadow);
  border: 1px solid var(--border);
  transition: var(--transition);
  display: flex;
  flex-direction: column;
  position: relative;
  overflow: hidden;
}
.testimonial-card::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 4px;
  background: var(--primary-gradient);
  transform: scaleX(0);
  transform-origin: left;
  transition: transform 0.5s var(--ease-out-quart);
}
.testimonial-card:hover { 
  transform: translateY(-10px);
  box-shadow: var(--shadow-hover);
}
.testimonial-card:hover::before {
  transform: scaleX(1);
}
.testimonial-content { 
  flex: 1; 
  margin-bottom: 25px;
}
.testimonial-content p {
  font-style: italic;
  color: var(--text);
  line-height: 1.8;
  font-size: 0.98rem;
  position: relative;
  padding: 0 0 0 15px;
}
.testimonial-content p::before { 
  content: '"';
  font-size: 2rem;
  color: var(--primary);
  line-height: 0.5;
  position: absolute;
  left: -5px;
  top: 0;
}
.testimonial-author { 
  display: flex; 
  align-items: center; 
  gap: 15px;
}
.author-image {
  width: 60px; height: 60px;
  border-radius: 50%;
  overflow: hidden;
  border: 3px solid var(--primary);
  background: linear-gradient(135deg, var(--primary), var(--secondary));
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1.6rem;
  color: white;
  flex-shrink: 0;
}
.testimonial-author h4 { 
  font-size: 1.05rem; 
  color: var(--text);
  font-weight: 700;
  margin-bottom: 3px;
}
.testimonial-author span {
  font-size: 0.9rem;
  color: var(--text-light);
}

/* ===== Partners ===== */
.partners-section {
  padding: 80px 0;
  background: var(--bg-alt);
  position: relative;
  overflow: hidden;
}
.partners-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(130px, 1fr));
  gap: 20px;
  margin-top: 40px;
}
.partner-logo {
  background: var(--card-bg);
  border-radius: 12px;
  padding: 20px;
  display: flex;
  align-items: center;
  justify-content: center;
  height: 90px;
  box-shadow: var(--shadow);
  transition: var(--transition);
  border: 1px solid var(--border);
}
.partner-logo:hover { transform: translateY(-5px); box-shadow: var(--shadow-hover); }
.partner-logo span {
  font-size: 0.8rem;
  color: var(--text-muted);
  font-weight: 600;
  text-align: center;
}

/* ===== Portfolio Gallery ===== */
.portfolio-slider-section { 
  padding: 100px 0; 
  overflow: hidden;
  position: relative;
}
.portfolio-scroll {
  display: flex;
  gap: 25px;
  overflow-x: auto;
  padding: 25px 0 35px;
  scroll-snap-type: x mandatory;
  -webkit-overflow-scrolling: touch;
  scroll-behavior: smooth;
  cursor: grab;
}
.portfolio-scroll:active { cursor: grabbing; }
.portfolio-scroll::-webkit-scrollbar { height: 8px; }
.portfolio-scroll::-webkit-scrollbar-track { background: var(--bg-alt); border-radius: 5px; }
.portfolio-scroll::-webkit-scrollbar-thumb { background: var(--primary-gradient); border-radius: 5px; }
.portfolio-item-snap {
  flex: 0 0 320px;
  height: 300px;
  border-radius: 24px;
  overflow: hidden;
  scroll-snap-align: start;
  box-shadow: var(--shadow);
  transition: var(--transition);
  position: relative;
  cursor: pointer;
  border: 1px solid var(--border);
}
.portfolio-item-snap:focus-visible { 
  outline: 3px solid var(--primary); 
  outline-offset: 4px;
}
.portfolio-item-snap:hover { 
  transform: translateY(-12px) scale(1.02);
  box-shadow: var(--shadow-hover);
  border-color: var(--primary);
}
.portfolio-item-snap .mockup-browser {
  width: 100%;
  height: 100%;
  display: flex;
  flex-direction: column;
  position: relative;
}
.portfolio-item-snap .mockup-bar {
  height: 24px;
  display: flex;
  align-items: center;
  gap: 5px;
  padding: 0 12px;
}
.portfolio-item-snap .mockup-dot {
  width: 7px; height: 7px;
  border-radius: 50%;
}
.portfolio-item-snap .mockup-url {
  font-size: 0.6rem;
  color: rgba(255,255,255,0.7);
  margin-right: auto;
  direction: ltr;
  text-align: left;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  max-width: 160px;
}
.portfolio-item-snap .mockup-content {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 15px;
  text-align: center;
  position: relative;
  transition: transform 0.4s var(--ease-out-quart);
}
.portfolio-item-snap .mockup-icon { font-size: 2.5rem; margin-bottom: 8px; transition: transform 0.3s var(--ease-out-quart); }
.portfolio-item-snap .mockup-title {
  font-size: 0.85rem;
  font-weight: 700;
  color: rgba(255,255,255,0.95);
}
.portfolio-item-snap .mockup-desc {
  font-size: 0.65rem;
  color: rgba(255,255,255,0.6);
  margin-top: 3px;
}
.portfolio-item-snap:hover .mockup-content { transform: scale(1.04); }
.portfolio-item-snap:hover .mockup-icon { transform: scale(1.15); }
.portfolio-item-snap:active { transform: translateY(-4px) scale(0.98); }
.portfolio-item-snap img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  transition: transform 0.5s var(--ease-out-quart);
}
.portfolio-item-snap:hover img { transform: scale(1.1); }
.portfolio-item-snap .overlay {
  position: absolute;
  bottom: 0; left: 0; right: 0;
  padding: 20px;
  background: linear-gradient(to top, rgba(0,0,0,0.85), transparent);
  color: white;
  opacity: 0;
  transition: opacity 0.3s var(--ease-out-quart);
  pointer-events: none;
}
.portfolio-item-snap:hover .overlay { opacity: 1; }
.portfolio-item-snap .overlay h4 { font-size: 1rem; margin-bottom: 5px; }
.portfolio-item-snap .overlay a {
  color: var(--primary-light);
  font-size: 0.85rem;
  display: flex;
  align-items: center;
  gap: 5px;
  pointer-events: auto;
}
.portfolio-item-snap .overlay a:focus-visible { outline: 2px solid white; outline-offset: 2px; border-radius: 4px; }

/* ===== Toast Notification ===== */
.copy-toast {
  position: fixed;
  bottom: 30px;
  left: 50%;
  transform: translateX(-50%) translateY(100px);
  background: linear-gradient(135deg, #10B981, #059669);
  color: white;
  padding: 15px 30px;
  border-radius: 50px;
  box-shadow: 0 10px 30px rgba(16, 185, 129, 0.4);
  z-index: 9999;
  opacity: 0;
  transition: all 0.4s var(--ease-out-quart);
  pointer-events: none;
  white-space: nowrap;
  font-weight: 600;
}
.copy-toast.show {
  opacity: 1;
  transform: translateX(-50%) translateY(0);
}

/* ===== Button Outline Glow ===== */
.btn-outline-glow {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 12px 28px;
  border-radius: 50px;
  background: transparent;
  color: var(--primary);
  border: 2px solid var(--primary);
  font-weight: 700;
  font-size: 0.95rem;
  cursor: pointer;
  transition: all 0.4s var(--ease-out-quart);
  text-decoration: none;
  position: relative;
}
.btn-outline-glow:hover {
  background: var(--primary-gradient);
  color: white;
  border-color: transparent;
  box-shadow: 0 5px 20px rgba(var(--primary-rgb), 0.3);
  transform: translateY(-2px);
}
.btn-outline-glow:active { transform: translateY(0) scale(0.98); }

/* ===== Primary Glow Button ===== */
.btn-primary-glow {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  padding: 14px 32px;
  border-radius: 50px;
  background: var(--primary-gradient);
  color: white;
  font-weight: 700;
  font-size: 1rem;
  border: none;
  cursor: pointer;
  transition: all 0.4s var(--ease-out-quart);
  text-decoration: none;
  box-shadow: 0 5px 20px rgba(var(--primary-rgb), 0.25);
}
.btn-primary-glow:hover {
  transform: translateY(-3px);
  box-shadow: 0 8px 30px rgba(var(--primary-rgb), 0.4);
  color: white;
}
.btn-primary-glow:active { transform: translateY(0) scale(0.97); }

/* ===== Store Links ===== */
.stores-section { 
  padding: 100px 0; 
}
.stores-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
  gap: 20px;
  margin-bottom: 35px;
}
.store-link-card {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 25px 18px;
  background: var(--card-bg);
  border-radius: 24px;
  border: 2px solid var(--border);
  text-decoration: none;
  transition: var(--transition);
  position: relative;
  overflow: hidden;
  box-shadow: var(--shadow);
}
.store-link-card::before {
  content: '';
  position: absolute;
  top: 0; left: 0; right: 0;
  height: 3px;
  background: var(--primary-gradient);
  transform: scaleX(0);
  transform-origin: left;
  transition: transform 0.5s var(--ease-out-quart);
}
.store-link-card:hover { 
  transform: translateY(-8px);
  border-color: var(--primary);
  box-shadow: var(--shadow-hover);
}
.store-link-card:hover::before { 
  transform: scaleX(1);
}
.store-link-card .store-icon {
  width: 60px; height: 60px;
  border-radius: 16px;
  background: linear-gradient(135deg, rgba(99,102,241,0.15), rgba(139,92,246,0.1));
  display: flex;
  align-items: center;
  justify-content: center;
  margin-bottom: 12px;
  font-size: 1.5rem;
  color: var(--primary);
  transition: var(--transition);
}
.store-link-card:hover .store-icon { 
  background: var(--primary-gradient);
  color: white;
  transform: scale(1.15) rotate(-10deg);
  box-shadow: 0 12px 30px rgba(99,102,241,0.3);
}
.store-link-card .store-name { 
  font-size: 1rem; 
  font-weight: 700; 
  color: var(--text); 
  margin-bottom: 5px;
}
.store-link-card .store-url { 
  font-size: 0.8rem; 
  color: var(--text-light); 
  direction: ltr;
}
.stores-actions { display: flex; justify-content: center; gap: 15px; flex-wrap: wrap; }
.action-btn {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 12px 24px;
  border-radius: 50px;
  font-weight: 700;
  font-size: 0.95rem;
  cursor: pointer;
  transition: var(--transition);
  border: none;
  text-decoration: none;
}
.copy-all-btn { background: var(--primary-gradient); color: white; box-shadow: 0 5px 15px rgba(var(--primary-rgb),0.3); }
.share-whatsapp-btn { background: linear-gradient(135deg,#25D366 0%,#128C7E 100%); color: white; }
.view-gallery-btn { background: var(--card-bg); color: var(--primary); border: 2px solid var(--primary); }
.action-btn:hover { transform: translateY(-3px); color: white; }
.view-gallery-btn:hover { background: var(--primary); color: white; }

/* ===== Discount Coupons ===== */
.discounts-section { 
  padding: 100px 0; 
  background: var(--bg-alt); 
  position: relative;
  overflow: hidden;
}
.discounts-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
  gap: 30px;
  margin-top: 50px;
}
.discount-card {
  background: var(--card-bg);
  border-radius: 24px;
  padding: 35px 30px;
  text-align: center;
  border: 1px solid var(--border);
  transition: var(--transition);
  position: relative;
  overflow: hidden;
  box-shadow: var(--shadow);
}
.discount-card::before {
  content: '';
  position: absolute;
  top: -50%;
  left: -50%;
  width: 200px;
  height: 200px;
  border-radius: 50%;
  background: radial-gradient(circle, rgba(99,102,241,0.1) 0%, transparent 70%);
  pointer-events: none;
  transition: all 0.5s var(--ease-out-quart);
}
.discount-card:hover { 
  transform: translateY(-10px);
  box-shadow: var(--shadow-hover);
  border-color: var(--primary);
}
.discount-card:hover::before {
  top: -20%;
  left: -20%;
}
.discount-card h3 { 
  font-size: 1.3rem; 
  margin-bottom: 15px; 
  color: var(--text);
  font-weight: 700;
}
.discount-card .code {
  font-size: 1.5rem;
  font-weight: 800;
  letter-spacing: 2px;
  color: var(--primary);
  background: linear-gradient(135deg, rgba(99,102,241,0.05), rgba(139,92,246,0.05));
  padding: 15px 20px;
  border-radius: 14px;
  display: inline-block;
  margin: 20px 0;
  font-family: 'Courier New', monospace;
  direction: ltr;
  border: 1px dashed var(--primary);
}
.discount-card .discount-actions { display: flex; gap: 12px; justify-content: center; margin-top: 20px; }
.discount-card .discount-actions .copy-btn {
  padding: 10px 20px;
  border-radius: 50px;
  background: var(--primary-gradient);
  color: white;
  border: none;
  font-weight: 700;
  cursor: pointer;
  transition: var(--transition);
  font-size: 0.9rem;
}
.discount-card .discount-actions .activate-btn {
  padding: 10px 20px;
  border-radius: 50px;
  background: transparent;
  color: var(--primary);
  border: 2px solid var(--primary);
  font-weight: 700;
  cursor: pointer;
  transition: var(--transition);
  text-decoration: none;
  font-size: 0.9rem;
}
.discount-card .discount-actions .activate-btn:hover {
  background: var(--primary-gradient);
  color: white;
  border-color: transparent;
}

/* ===== Creators Tools ===== */
.tools-section { 
  padding: 100px 0; 
  position: relative;
}
.tools-horizontal-grid {
  display: flex;
  justify-content: center;
  flex-wrap: wrap;
  gap: 25px;
  max-width: 1400px;
  margin: 0 auto;
}
.tool-squircle {
  width: 140px; height: 140px;
  background: var(--card-bg);
  border-radius: 35px;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  text-decoration: none;
  transition: var(--transition);
  border: 1px solid var(--border);
  box-shadow: var(--shadow);
  position: relative;
  overflow: hidden;
}
.tool-squircle::before {
  content: '';
  position: absolute;
  inset: 0;
  background: linear-gradient(135deg, rgba(99,102,241,0.05) 0%, transparent 100%);
  opacity: 0;
  transition: opacity 0.3s ease;
  pointer-events: none;
}
.tool-squircle:hover {
  transform: translateY(-12px) scale(1.08);
  box-shadow: var(--shadow-hover);
  border-color: var(--primary);
}
.tool-squircle:hover::before {
  opacity: 1;
}
.tool-squircle .tool-icon {
  font-size: 2.5rem;
  color: var(--primary);
  margin-bottom: 12px;
  transition: var(--transition);
  position: relative;
  z-index: 1;
}
.tool-squircle:hover .tool-icon { 
  transform: scale(1.2) rotate(10deg);
  color: var(--secondary);
  text-shadow: 0 8px 20px rgba(99,102,241,0.3);
}
.tool-squircle .tool-name { 
  font-size: 0.9rem; 
  font-weight: 700; 
  color: var(--text); 
  text-align: center;
  position: relative;
  z-index: 1;
}

/* ===== Theme Detector Game ===== */
.theme-detector-game {
  padding: 80px 0;
  background: var(--bg-alt);
  position: relative;
}
.quest-banner {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 20px 30px;
  background: var(--primary-gradient);
  border-radius: 20px;
  color: white;
  margin-bottom: 30px;
}
.quest-banner h2 { font-size: 1.3rem; color: white; }
.live-counter { display: flex; align-items: center; gap: 8px; font-size: 0.9rem; }
.pulse-dot {
  width: 10px; height: 10px;
  background: #22c55e;
  border-radius: 50%;
  animation: pulse 2s infinite;
}
@keyframes pulse {
  0%, 100% { transform: scale(1); opacity: 1; }
  50% { transform: scale(1.5); opacity: 0.5; }
}
.mission-card {
  background: var(--card-bg);
  border-radius: 24px;
  padding: 40px;
  text-align: center;
  box-shadow: var(--shadow);
  max-width: 600px;
  margin: 0 auto;
  border: 1px solid var(--border);
}
.mission-card h3 { font-size: 1.5rem; color: var(--primary); margin-bottom: 15px; }
.mission-card p { color: var(--text-light); margin-bottom: 25px; }
.game-buttons { display: flex; gap: 15px; justify-content: center; flex-wrap: wrap; }
.game-btn {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 14px 28px;
  border-radius: 50px;
  border: none;
  font-weight: 700;
  font-size: 0.95rem;
  cursor: pointer;
  transition: var(--transition);
}
.chrome-btn { background: #4285F4; color: white; }
.edge-btn { background: #0078D7; color: white; }
.game-btn:hover { transform: translateY(-3px); box-shadow: 0 8px 20px rgba(0,0,0,0.2); }
.scarcity-notice {
  margin-top: 20px;
  padding: 12px;
  background: rgba(239,68,68,0.1);
  border-radius: 12px;
  color: #ef4444;
  font-size: 0.9rem;
}

/* ===== Contact ===== */
.contact-section { 
  padding: 100px 0; 
  position: relative;
}
.contact-grid-wrapper {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 50px;
  max-width: 1100px;
  margin: 0 auto;
}
.contact-card-modern, .contact-form-card {
  background: var(--card-bg);
  border-radius: 24px;
  padding: 45px;
  box-shadow: var(--shadow);
  border: 1px solid var(--border);
  position: relative;
  overflow: hidden;
}
.contact-card-modern::before,
.contact-form-card::before {
  content: '';
  position: absolute;
  top: -50%;
  right: -50%;
  width: 400px;
  height: 400px;
  border-radius: 50%;
  background: radial-gradient(circle, rgba(99,102,241,0.08) 0%, transparent 70%);
  pointer-events: none;
}
.contact-card-modern .contact-header h2,
.contact-form-card .contact-header h2 { 
  font-size: 1.6rem; 
  color: var(--text);
  margin-bottom: 10px; 
  font-weight: 700;
}
.contact-card-modern .contact-header p,
.contact-form-card .contact-header p { 
  color: var(--text-light); 
  font-size: 1rem; 
  margin-bottom: 30px;
}
.contact-list { 
  display: flex; 
  flex-direction: column; 
  gap: 18px;
  position: relative;
  z-index: 1;
}
.contact-item {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 18px 22px;
  background: linear-gradient(135deg, rgba(99,102,241,0.05), transparent);
  border-radius: 16px;
  transition: var(--transition);
  border: 1px solid var(--border);
}
.contact-item:hover { 
  transform: translateX(-8px);
  background: linear-gradient(135deg, rgba(99,102,241,0.1), rgba(139,92,246,0.05));
  border-color: var(--primary);
}
.contact-item .contact-text h3 { 
  font-size: 1rem; 
  color: var(--text); 
  margin-bottom: 4px;
  font-weight: 700;
}
.contact-item .contact-text span { 
  font-size: 0.9rem; 
  color: var(--text-light);
}
.contact-item .contact-icon-box {
  width: 50px; height: 50px;
  border-radius: 14px;
  background: linear-gradient(135deg, rgba(99,102,241,0.15), rgba(139,92,246,0.1));
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1.4rem;
  color: var(--primary);
  transition: var(--transition);
  flex-shrink: 0;
}
.contact-item:hover .contact-icon-box {
  background: var(--primary-gradient);
  color: white;
  transform: scale(1.1);
}
.whatsapp-full-btn {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
  width: 100%;
  padding: 18px;
  margin-top: 30px;
  border-radius: 16px;
  background: linear-gradient(135deg, #25D366 0%, #128C7E 100%);
  color: white !important;
  font-weight: 700;
  font-size: 1.1rem;
  transition: var(--transition);
  text-decoration: none;
  border: none;
  cursor: pointer;
  box-shadow: 0 8px 25px rgba(37,211,102,0.3);
  position: relative;
  z-index: 1;
}
.whatsapp-full-btn:hover { 
  transform: translateY(-4px);
  box-shadow: 0 12px 35px rgba(37,211,102,0.5);
}
.form-tabs {
  display: flex;
  gap: 12px;
  margin-bottom: 30px;
  position: relative;
  z-index: 1;
}
.form-tab {
  flex: 1;
  padding: 14px;
  border-radius: 14px;
  border: 2px solid var(--border);
  background: transparent;
  color: var(--text-light);
  font-weight: 700;
  font-size: 0.95rem;
  cursor: pointer;
  transition: var(--transition);
  font-family: inherit;
}
.form-tab.active {
  border-color: var(--primary);
  background: linear-gradient(135deg, rgba(99,102,241,0.1), rgba(139,92,246,0.05));
  color: var(--primary);
}
.form-group { 
  margin-bottom: 25px;
  position: relative;
  z-index: 1;
}
.form-group label { 
  display: block; 
  font-weight: 600; 
  margin-bottom: 10px; 
  color: var(--text); 
  font-size: 0.95rem;
}
.form-group input,
.form-group textarea,
.form-group select {
  width: 100%;
  padding: 14px 16px;
  border: 2px solid var(--border);
  border-radius: 14px;
  font-size: 1rem;
  font-family: inherit;
  background: var(--bg);
  color: var(--text);
  transition: var(--transition);
}
.form-group input:focus,
.form-group textarea:focus,
.form-group select:focus {
  outline: none;
  border-color: var(--primary);
  box-shadow: 0 0 0 5px rgba(99,102,241,0.1);
  transform: translateY(-2px);
}
.form-group textarea { 
  resize: vertical; 
  min-height: 120px;
}

/* ===== Help Section ===== */
.help-section { 
  padding: 100px 0; 
  background: var(--bg-alt); 
}
.help-section h2 { 
  text-align: center; 
  font-size: 2.5rem; 
  color: var(--text);
  margin-bottom: 50px; 
  font-weight: 800;
}
.help-cards { 
  display: grid; 
  grid-template-columns: repeat(auto-fill, minmax(320px, 1fr)); 
  gap: 35px; 
}
.help-card {
  background: var(--card-bg);
  border-radius: 24px;
  padding: 40px 35px;
  box-shadow: var(--shadow);
  transition: var(--transition);
  border: 1px solid var(--border);
  position: relative;
  overflow: hidden;
}
.help-card::before {
  content: '';
  position: absolute;
  top: -50%;
  right: -50%;
  width: 300px;
  height: 300px;
  border-radius: 50%;
  background: radial-gradient(circle, rgba(99,102,241,0.08) 0%, transparent 70%);
  pointer-events: none;
  transition: all 0.5s var(--ease-out-quart);
}
.help-card:hover { 
  transform: translateY(-12px);
  box-shadow: var(--shadow-hover);
}
.help-card:hover::before {
  top: -30%;
  right: -30%;
}
.help-card-icon {
  width: 70px; height: 70px;
  border-radius: 18px;
  background: linear-gradient(135deg, rgba(99,102,241,0.15), rgba(139,92,246,0.1));
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1.8rem;
  color: var(--primary);
  margin-bottom: 25px;
  transition: var(--transition);
  position: relative;
  z-index: 1;
}
.help-card:hover .help-card-icon { 
  background: var(--primary-gradient);
  color: white;
  transform: scale(1.15) rotate(8deg);
  box-shadow: 0 12px 30px rgba(99,102,241,0.3);
}
.help-card h3 { 
  font-size: 1.3rem; 
  color: var(--text);
  margin-bottom: 15px; 
  font-weight: 700;
}
.help-card p { 
  color: var(--text-light); 
  font-size: 0.98rem; 
  line-height: 1.8;
  margin-bottom: 20px; 
}
.help-card-features { display: flex; flex-direction: column; gap: 10px; }
.help-card-features span {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 0.9rem;
  color: var(--text);
}

/* ===== Vision & Mission ===== */
.vision-mission-content-centered {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 30px;
  max-width: 900px;
  margin: 0 auto;
}
.vision-box, .mission-box {
  background: var(--card-bg);
  border-radius: 20px;
  padding: 35px;
  text-align: center;
  box-shadow: var(--shadow);
  border: 1px solid var(--border);
  transition: var(--transition);
}
.vision-box:hover, .mission-box:hover { transform: translateY(-8px); box-shadow: var(--shadow-hover); }
.vision-box h3, .mission-box h3 { font-size: 1.3rem; color: var(--primary); margin: 15px 0 10px; }
.vision-box p, .mission-box p { color: var(--text-light); font-size: 0.95rem; line-height: 1.7; }
.values-grid-centered {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(230px, 1fr));
  gap: 25px;
  max-width: 1000px;
  margin: 40px auto 0;
}
.value-card {
  background: var(--card-bg);
  border-radius: 18px;
  padding: 30px;
  text-align: center;
  box-shadow: var(--shadow);
  border: 1px solid var(--border);
  transition: var(--transition);
}
.value-card:hover { transform: translateY(-6px); box-shadow: var(--shadow-hover); }
.value-card h3 { font-size: 1.1rem; color: var(--primary); margin: 12px 0 8px; }
.value-card p { color: var(--text-light); font-size: 0.9rem; line-height: 1.6; }

/* ===== CTA ===== */
.cta-section { padding: 80px 0; background: var(--bg-alt); }
.cta-content-centered {
  text-align: center;
  max-width: 650px;
  margin: 0 auto;
}
.cta-content-centered h2 { font-size: 2rem; color: var(--primary); margin-bottom: 15px; }
.cta-content-centered p { color: var(--text-light); font-size: 1.05rem; margin-bottom: 30px; }

/* ===== Floating WhatsApp ===== */
.floating-whatsapp {
  position: fixed;
  bottom: 30px;
  left: 30px;
  width: 64px; height: 64px;
  background: linear-gradient(135deg, #25D366 0%, #128C7E 100%);
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  color: white !important;
  font-size: 1.8rem;
  box-shadow: 0 8px 30px rgba(37,211,102,0.5);
  z-index: 998;
  transition: var(--transition);
  cursor: pointer;
  text-decoration: none;
  border: 3px solid white;
}
.floating-whatsapp:hover {
  transform: scale(1.15) translateY(-8px);
  box-shadow: 0 12px 40px rgba(37,211,102,0.7);
}
.floating-whatsapp:active {
  transform: scale(0.95);
}

/* ===== Scrolling Logos ===== */
.scrolling-logos-container {
  overflow: hidden;
  padding: 40px 0;
  background: var(--bg-alt);
  position: relative;
}
.scrolling-logos {
  display: flex;
  gap: 60px;
  animation: scrollLogos 35s linear infinite;
  width: max-content;
}
.scrolling-logos .logo-item {
  flex: 0 0 auto;
  padding: 12px 35px;
  background: linear-gradient(135deg, rgba(99,102,241,0.08), rgba(139,92,246,0.05));
  border-radius: 14px;
  border: 1px solid var(--border);
  font-weight: 700;
  color: var(--text-light);
  font-size: 1.1rem;
  white-space: nowrap;
  transition: var(--transition);
  display: flex;
  align-items: center;
  gap: 8px;
}
.scrolling-logos .logo-svg {
  width: 20px;
  height: 20px;
  flex-shrink: 0;
  color: var(--primary);
  transition: var(--transition);
}
.scrolling-logos .logo-item:hover {
  color: var(--primary);
  background: linear-gradient(135deg, rgba(99,102,241,0.15), rgba(139,92,246,0.1));
  transform: translateY(-3px);
}
.scrolling-logos .logo-item:hover .logo-svg {
  transform: scale(1.15) rotate(-5deg);
}
@keyframes scrollLogos {
  0% { transform: translateX(0); }
  100% { transform: translateX(-50%); }
}

/* ===== Back to Top ===== */
.back-to-top {
  position: fixed;
  bottom: 30px;
  right: 30px;
  width: 58px; height: 58px;
  background: var(--primary-gradient);
  color: white;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1.5rem;
  cursor: pointer;
  z-index: 997;
  opacity: 0;
  visibility: hidden;
  transition: var(--transition);
  border: none;
  box-shadow: 0 8px 30px rgba(99,102,241,0.5);
}
.back-to-top.show { 
  opacity: 1; 
  visibility: visible;
}
.back-to-top:hover { 
  transform: translateY(-6px);
  box-shadow: 0 12px 40px rgba(99,102,241,0.7);
}
.back-to-top:active {
  transform: scale(0.95);
}

/* ===== Blogger Post Styles ===== */
.post { margin-bottom: 40px; }
.post-title { font-size: 2rem; color: var(--primary); margin-bottom: 15px; }
.post-body { color: var(--text); line-height: 1.9; font-size: 1rem; }
.post-body h2, .post-body h3 { color: var(--primary); margin: 25px 0 15px; }
.post-body p { margin-bottom: 15px; }
.post-body img { border-radius: 12px; margin: 20px 0; }
.post-meta {
  display: flex;
  gap: 20px;
  color: var(--text-light);
  font-size: 0.85rem;
  margin-bottom: 20px;
  padding-bottom: 20px;
  border-bottom: 1px solid var(--border);
}
.post-footer {
  margin-top: 30px;
  padding-top: 20px;
  border-top: 1px solid var(--border);
}

/* ===== Sidebar Widgets ===== */
.widget { margin-bottom: 40px; }
.widget h2 {
  font-size: 1.3rem;
  color: var(--primary);
  margin-bottom: 20px;
  padding-bottom: 10px;
  border-bottom: 3px solid var(--primary);
}
.PopularPosts .item-title { font-size: 0.95rem; font-weight: 600; margin-bottom: 5px; }
.PopularPosts .item-snippet { color: var(--text-light); font-size: 0.85rem; }

/* ===== Footer ===== */
.footer {
  background: linear-gradient(135deg, #0f172a 0%, #1e293b 50%, #334155 100%);
  color: white;
  padding: 80px 0 30px;
  position: relative;
  overflow: hidden;
}
.footer::before {
  content: '';
  position: absolute;
  inset: 0;
  background: 
    radial-gradient(circle at 20% 50%, rgba(99,102,241,0.1) 0%, transparent 50%),
    radial-gradient(circle at 80% 80%, rgba(139,92,246,0.08) 0%, transparent 50%);
  pointer-events: none;
  opacity: 0.3;
  z-index: 0;
}
.footer-content {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
  gap: 50px;
  margin-bottom: 50px;
  position: relative;
  z-index: 1;
}
.footer h3 {
  font-size: 1.25rem;
  margin-bottom: 25px;
  position: relative;
  color: white;
  font-weight: 700;
}
.footer h3::after {
  content: '';
  position: absolute;
  bottom: -10px;
  right: 0;
  width: 50px;
  height: 3px;
  background: var(--primary-gradient);
  border-radius: 2px;
}
.footer-about p { 
  color: rgba(255,255,255,0.75); 
  font-size: 0.95rem; 
  line-height: 1.8;
}
.footer-links ul { 
  display: flex; 
  flex-direction: column; 
  gap: 15px; 
}
.footer-links ul li a { 
  color: rgba(255,255,255,0.75); 
  transition: var(--transition); 
  font-size: 0.95rem;
  display: flex;
  align-items: center;
  gap: 8px;
}
.footer-links ul li a::before {
  content: '→';
  opacity: 0;
  transform: translateX(-8px);
  transition: all 0.3s var(--ease-out-quart);
}
.footer-links ul li a:hover { 
  color: var(--primary-light);
  transform: translateX(5px);
}
.footer-links ul li a:hover::before {
  opacity: 1;
  transform: translateX(0);
}
.footer-social {
  display: flex;
  gap: 12px;
  margin-top: 25px;
  flex-wrap: wrap;
}
.footer-social a {
  width: 44px; height: 44px;
  border-radius: 50%;
  background: rgba(255,255,255,0.1);
  display: flex;
  align-items: center;
  justify-content: center;
  color: white;
  transition: var(--transition);
  text-decoration: none;
  font-size: 1rem;
  border: 1px solid rgba(255,255,255,0.2);
}
.footer-social a:hover { 
  background: var(--primary-gradient);
  border-color: transparent;
  transform: translateY(-5px);
  box-shadow: 0 8px 25px rgba(99,102,241,0.3);
  color: white;
}
.footer-bottom {
  text-align: center;
  padding-top: 30px;
  border-top: 1px solid rgba(255,255,255,0.1);
  position: relative;
  z-index: 1;
}
.footer-bottom p { 
  font-size: 0.9rem; 
  color: rgba(255,255,255,0.65);
  margin: 0;
}

/* ===== Responsive ===== */
@media (max-width: 992px) {
  .hero-content h1 { font-size: 2.8rem; }
  .hero-content > p { font-size: 1.1rem; }
  .section-title h2 { font-size: 2.1rem; }
  .services-grid { grid-template-columns: repeat(2, 1fr); }
  .contact-grid-wrapper { grid-template-columns: 1fr; }
  .vision-mission-content-centered { grid-template-columns: 1fr; }
  .stores-grid { grid-template-columns: repeat(3, 1fr); }
}

@media (max-width: 768px) {
  .hero-content h1 { font-size: 2.3rem; }
  .hero-content > p { font-size: 1rem; }
  .hero-btn { padding: 16px 32px; font-size: 1rem; }
  .section-title h2 { font-size: 1.9rem; }
  .section-title h2::after { width: 50px; }
  .section { padding: 70px 0; }
  .service-card { padding: 35px 25px; }
  .service-icon { width: 70px; height: 70px; font-size: 1.8rem; }
  .stat-number { font-size: 2.6rem; }
  .stats-grid { grid-template-columns: repeat(2, 1fr); gap: 25px; }
  .help-cards { grid-template-columns: repeat(2, 1fr); gap: 25px; }
  .testimonials-grid { grid-template-columns: 1fr; }
  .services-grid { grid-template-columns: 1fr; }
  .stores-grid { grid-template-columns: repeat(2, 1fr); }
  .contact-grid-wrapper { grid-template-columns: 1fr; gap: 30px; }
  .contact-card-modern, .contact-form-card { padding: 30px; }
  .form-group input, .form-group textarea { padding: 12px 14px; }
  .floating-whatsapp { width: 56px; height: 56px; font-size: 1.5rem; bottom: 20px; left: 20px; }
  .back-to-top { width: 50px; height: 50px; font-size: 1.2rem; bottom: 20px; right: 20px; }
  .discounts-grid { grid-template-columns: 1fr; }
  .quest-banner { flex-direction: column; gap: 10px; text-align: center; }
  .stores-actions { flex-direction: column; }
  .action-btn { width: 100%; justify-content: center; }
}

@media (max-width: 600px) {
  .hero-section { min-height: 70vh; padding: 100px 0 40px; }
  .hero-content h1 { font-size: 1.9rem; line-height: 1.1; }
  .hero-content > p { font-size: 0.95rem; margin-bottom: 25px; }
  .hero-btn { padding: 14px 28px; font-size: 0.95rem; gap: 8px; }
  .header { top: 15px; width: 95%; padding: 8px 15px; }
  .nav { width: 280px; max-width: 85%; }
  .header-whatsapp-btn span { display: none; }
  .stats-grid { grid-template-columns: 1fr; gap: 20px; }
  .stat-number { font-size: 2.2rem; }
  .help-cards { grid-template-columns: 1fr; gap: 20px; }
  .section-title h2 { font-size: 1.6rem; }
  .section-title h2::after { width: 40px; }
  .section { padding: 60px 0; }
  .service-card { padding: 30px 20px; margin-bottom: 20px; }
  .service-icon { width: 65px; height: 65px; font-size: 1.6rem; margin-bottom: 18px; }
  .tool-squircle { width: 110px; height: 110px; }
  .tool-squircle .tool-icon { font-size: 2.2rem; margin-bottom: 8px; }
  .tool-squircle .tool-name { font-size: 0.85rem; }
  .tools-horizontal-grid { gap: 20px; }
  .discounts-grid { grid-template-columns: 1fr; }
  .discount-card { padding: 25px 20px; }
  .discount-card .code { font-size: 1.2rem; }
  .partners-grid { grid-template-columns: repeat(2, 1fr); gap: 15px; }
  .stores-grid { grid-template-columns: 1fr; }
  .portfolio-scroll { padding: 15px 0 25px; gap: 15px; }
  .portfolio-item-snap { flex: 0 0 270px; height: 240px; }
  .contact-card-modern, .contact-form-card { padding: 25px; }
  .contact-item { padding: 15px 16px; }
  .contact-item .contact-text h3 { font-size: 0.95rem; }
  .contact-item .contact-icon-box { width: 45px; height: 45px; font-size: 1.2rem; }
  .floating-whatsapp { width: 52px; height: 52px; font-size: 1.4rem; bottom: 15px; left: 15px; }
  .back-to-top { width: 48px; height: 48px; font-size: 1.1rem; bottom: 15px; right: 15px; }
  .blog-layout { flex-direction: column; }
  .blog-sidebar { width: 100%; }
  .blog-post-card .post-title { font-size: 1.3rem; }
  .blog-single .post-title { font-size: 1.5rem; }
  .footer-content { grid-template-columns: 1fr; gap: 30px; }
}

@media (pointer: coarse) {
  .nav-links li a { 
    padding: 14px 22px; 
    min-height: 48px; 
    display: flex; 
    align-items: center;
  }
  .theme-toggle, .mobile-toggle { 
    width: 48px; 
    height: 48px;
    font-size: 1.2rem;
  }
  .service-card { padding: 35px 28px; }
  .stat-item { padding: 38px 25px; }
  .help-card { padding: 38px 32px; }
  .btn, .btn-primary-glow { 
    padding: 16px 36px; 
    min-height: 48px;
  }
  .store-link-card { padding: 25px 18px; }
  .tool-squircle { 
    min-width: 140px; 
    min-height: 140px;
  }
  .form-group input,
  .form-group textarea,
  .form-group select {
    min-height: 48px;
  }
}

@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
    scroll-behavior: auto !important;
  }
}

/* ===== Page Header (for inner pages) ===== */
.page-header {
  padding: 140px 0 30px;
  text-align: center;
  background: linear-gradient(135deg, rgba(var(--primary-rgb),0.1), rgba(var(--primary-rgb),0.05));
  border-radius: 0 0 var(--radius-lg) var(--radius-lg);
  margin-bottom: 30px;
}
.page-header h1 { font-size: 2.5rem; color: var(--primary); margin-bottom: 10px; }
.page-header p { color: var(--text-light); font-size: 1.05rem; }

/* ===== Tab Panels ===== */
.tab-panels { width: 100%; }
.tab-panel { display: none; }
.tab-panel.active { display: block; }
.tab-panel.active .hero-section { display: flex; }

/* Tab switching animation */
.tab-panel.active { animation: tabFadeIn 0.35s var(--ease-out-quart); will-change: transform, opacity; }
@keyframes tabFadeIn {
  from { opacity: 0; transform: translateY(16px); }
  to { opacity: 1; transform: translateY(0); }
}
.tab-panel.active .hero-section { animation: heroFadeIn 0.5s var(--ease-out-expo); }
@keyframes heroFadeIn {
  from { opacity: 0; transform: translateY(24px) scale(0.98); }
  to { opacity: 1; transform: translateY(0) scale(1); }
}
@media (prefers-reduced-motion: reduce) {
  .tab-panel.active, .tab-panel.active .hero-section { animation: none; }
}

/* Blog Styles */
.blog-container {
  padding: 140px 0 60px;
  max-width: 1200px;
  margin: 0 auto;
  padding-left: 20px;
  padding-right: 20px;
}
.blog-layout { display: flex; gap: 40px; align-items: flex-start; }
.blog-posts { flex: 1; min-width: 0; }
.blog-sidebar { width: 320px; flex-shrink: 0; }
.blog-post-card {
  background: var(--card-bg);
  border-radius: var(--radius-lg);
  padding: 30px;
  margin-bottom: 25px;
  border: 1px solid var(--border);
  transition: var(--transition);
}
.blog-post-card:hover { box-shadow: var(--shadow-hover); transform: translateY(-3px); }
.blog-post-card .post-title { font-size: 1.5rem; margin-bottom: 12px; }
.blog-post-card .post-title a { color: var(--text); }
.blog-post-card .post-title a:hover { color: var(--primary); }
.blog-post-meta { display: flex; gap: 15px; flex-wrap: wrap; margin-bottom: 15px; font-size: 0.85rem; color: var(--text-light); }
.blog-post-meta span { display: flex; align-items: center; gap: 5px; }
.blog-post-body { color: var(--text); line-height: 1.9; font-size: 1rem; }
.blog-post-body img { max-width: 100%; border-radius: var(--radius); margin: 15px 0; }
.read-more {
  display: inline-block;
  margin-top: 15px;
  padding: 10px 25px;
  background: var(--primary-gradient);
  color: white;
  border-radius: 50px;
  font-weight: 600;
  font-size: 0.9rem;
  transition: var(--transition);
}
.read-more:hover { transform: translateY(-2px); box-shadow: var(--shadow-hover); color: white; }
.blog-pagination {
  display: flex;
  justify-content: center;
  gap: 10px;
  margin: 40px 0;
}
.blog-pagination a {
  padding: 10px 20px;
  background: var(--card-bg);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  color: var(--text);
  font-weight: 500;
  transition: var(--transition);
}
.blog-pagination a:hover { background: var(--primary-gradient); color: white; border-color: transparent; }

/* Single Post */
.blog-single { padding: 140px 0 60px; max-width: 800px; margin: 0 auto; padding-left: 20px; padding-right: 20px; }
.blog-single .post-title { font-size: 2rem; margin-bottom: 15px; color: var(--text); }
.blog-single .blog-post-body { font-size: 1.05rem; }

/* Comments */
.comments-section { margin-top: 50px; padding-top: 30px; border-top: 1px solid var(--border); }
.comments-section h3 { font-size: 1.3rem; margin-bottom: 20px; color: var(--text); }
.comments-section .comment { padding: 20px; background: var(--bg-alt); border-radius: var(--radius); margin-bottom: 15px; }
.comments-section .comment-header { display: flex; align-items: center; gap: 10px; margin-bottom: 10px; }
.comments-section .comment-author { font-weight: 700; color: var(--text); }
.comments-section .comment-date { font-size: 0.8rem; color: var(--text-light); }
.comments-section .comment-body { color: var(--text); line-height: 1.7; }

/* Sidebar */
.blog-sidebar .sidebar-widget {
  background: var(--card-bg);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  padding: 25px;
  margin-bottom: 25px;
}
.blog-sidebar .sidebar-widget h3 {
  font-size: 1.1rem;
  margin-bottom: 15px;
  padding-bottom: 10px;
  border-bottom: 2px solid var(--primary);
  color: var(--text);
}
.blog-sidebar .sidebar-widget ul { list-style: none; padding: 0; }
.blog-sidebar .sidebar-widget ul li { margin-bottom: 8px; }
.blog-sidebar .sidebar-widget ul li a {
  color: var(--text-light);
  padding: 5px 0;
  display: block;
  transition: var(--transition);
}
.blog-sidebar .sidebar-widget ul li a:hover { color: var(--primary); padding-right: 5px; }

@media (max-width: 768px) {
  .blog-layout { flex-direction: column; }
  .blog-sidebar { width: 100%; }
  .blog-post-card .post-title { font-size: 1.2rem; }
  .blog-single .post-title { font-size: 1.5rem; }
}

body.script:
//
/* =====================================
   قالب بلوجر احترافي - مصمم متاجر سلة و زد ورمز
   جميع الحقوق محفوظة Ali Ahmed © <data:blog.title/>
   ===================================== */

// تهيئة القالب
document.addEventListener('DOMContentLoaded', function() {
  initTheme();
  initMobileMenu();
  initScrollHeader();
  initStatsCounter();
  initBackToTop();
  initYear();
  initActiveNav();
  initTabSwipe();
});

// ===== نظام الألوان =====
function initTheme() {
  const saved = localStorage.getItem('blogger_theme');
  if (saved === 'dark') {
    document.documentElement.setAttribute('data-theme', 'dark');
  } else if (saved === 'light') {
    document.documentElement.setAttribute('data-theme', 'light');
  } else if (window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches) {
    document.documentElement.setAttribute('data-theme', 'dark');
  }
  const btn = document.querySelector('.theme-toggle');
  if (btn) btn.textContent = (document.documentElement.getAttribute('data-theme') === 'dark') ? '☀️' : '🌙';
}

function toggleTheme() {
  const current = document.documentElement.getAttribute('data-theme');
  const next = current === 'dark' ? 'light' : 'dark';
  document.documentElement.setAttribute('data-theme', next);
  localStorage.setItem('blogger_theme', next);
  const btn = document.querySelector('.theme-toggle');
  if (btn) btn.textContent = next === 'dark' ? '☀️' : '🌙';
}

// ===== القائمة المتنقلة =====
function initMobileMenu() {
  const toggle = document.querySelector('.mobile-toggle');
  const nav = document.querySelector('.nav');
  if (!toggle || !nav) return;

  toggle.addEventListener('click', function() {
    nav.classList.toggle('active');
    toggle.textContent = nav.classList.contains('active') ? '✕' : '☰';
  });

  nav.querySelectorAll('a').forEach(function(link) {
    link.addEventListener('click', function() {
      nav.classList.remove('active');
      toggle.textContent = '☰';
    });
  });
}

// ===== تأثير التمرير للهيدر =====
function initScrollHeader() {
  window.addEventListener('scroll', function() {
    const header = document.querySelector('.header');
    if (!header) return;
    if (window.scrollY > 50) {
      header.classList.add('scrolled');
    } else {
      header.classList.remove('scrolled');
    }
  });
}

// ===== عداد الإحصائيات المتحرك =====
function initStatsCounter() {
  const counters = document.querySelectorAll('.stat-number');
  if (!counters.length) return;

  const observer = new IntersectionObserver(function(entries) {
    entries.forEach(function(entry) {
      if (entry.isIntersecting) {
        const target = parseInt(entry.target.getAttribute('data-target'));
        animateCounter(entry.target, target);
        observer.unobserve(entry.target);
      }
    });
  }, { threshold: 0.5 });

  counters.forEach(function(counter) {
    observer.observe(counter);
  });
}

function animateCounter(el, target) {
  let current = 0;
  const increment = Math.ceil(target / 40);
  const timer = setInterval(function() {
    current += increment;
    if (current >= target) {
      current = target;
      clearInterval(timer);
    }
    el.textContent = current;
  }, 40);
}

// ===== زر العودة للأعلى =====
function initBackToTop() {
  const btn = document.querySelector('.back-to-top');
  if (!btn) return;

  window.addEventListener('scroll', function() {
    if (window.scrollY > 400) {
      btn.classList.add('show');
    } else {
      btn.classList.remove('show');
    }
  });

  btn.addEventListener('click', function() {
    window.scrollTo({ top: 0, behavior: 'smooth' });
  });
}

// ===== تحديث السنة =====
function initYear() {
  const el = document.getElementById('currentYear');
  if (el) el.textContent = new Date().getFullYear();
}

// ===== نسخ النص =====
function copyCode(code, btn) {
  function done() {
    const orig = btn.textContent;
    btn.textContent = '✅ تم النسخ';
    btn.style.background = '#10B981';
    btn.disabled = true;
    setTimeout(function() {
      btn.textContent = orig;
      btn.style.background = '';
      btn.disabled = false;
    }, 2000);
  }
  if (navigator.clipboard && navigator.clipboard.writeText) {
    navigator.clipboard.writeText(code).then(done, function() {
      fallbackCopy(code, done);
    });
  } else {
    fallbackCopy(code, done);
  }
}
function fallbackCopy(text, callback) {
  var ta = document.createElement('textarea');
  ta.value = text;
  ta.style.position = 'fixed'; ta.style.left = '-9999px';
  document.body.appendChild(ta);
  ta.select();
  document.execCommand('copy');
  document.body.removeChild(ta);
  if (callback) callback();
}

// ===== إرسال واتساب =====
function sendToWhatsApp(event) {
  event.preventDefault();
  const name = document.getElementById('contact-name');
  const email = document.getElementById('contact-email');
  const message = document.getElementById('contact-message');
  const storeUrl = document.getElementById('contact-store-url');
  const serviceType = document.getElementById('contact-service-type');

  let whatsappMessage = 'مرحباً، ';
  const isQuote = document.getElementById('quote-fields') ? document.getElementById('quote-fields').style.display !== 'none' : true;

  if (isQuote) {
    whatsappMessage += 'أرغب في طلب تسعير خدمة.\n\n';
  } else {
    whatsappMessage += 'لدي استفسار عام.\n\n';
  }

  whatsappMessage += '📋 *بياناتي:*\n';
  whatsappMessage += '👤 الاسم: ' + (name ? name.value : '') + '\n';
  whatsappMessage += '📧 البريد: ' + (email ? email.value : '') + '\n';
  if (isQuote && storeUrl && storeUrl.value) {
    whatsappMessage += '🔗 رابط المتجر: ' + storeUrl.value + '\n';
  }
  if (isQuote && serviceType && serviceType.value) {
    whatsappMessage += '🛠️ نوع الخدمة: ' + serviceType.value + '\n';
  }
  if (message && message.value) {
    whatsappMessage += '\n📝 *الرسالة:*\n' + message.value;
  }

  window.open('https://wa.me/201002241591?text=' + encodeURIComponent(whatsappMessage), '_blank');
}

// ===== تبديل تبويب النموذج =====
function switchFormTab(event, tabName) {
  const tabs = document.querySelectorAll('.form-tab');
  tabs.forEach(function(t) { t.classList.remove('active'); });
  if (event && event.currentTarget) event.currentTarget.classList.add('active');

  const quoteFields = document.getElementById('quote-fields');
  if (quoteFields) {
    quoteFields.style.display = tabName === 'quote' ? 'block' : 'none';
  }
}

// ===== نسخ روابط المتاجر =====
function copyAllStoreLinks() {
  const links = document.querySelectorAll('.store-link-card');
  let text = '';
  links.forEach(function(link) {
    text += link.getAttribute('data-store') || link.href + '\n';
  });
  navigator.clipboard.writeText(text).then(function() {
    const toast = document.getElementById('copy-toast');
    if (toast) {
      toast.classList.add('show');
      setTimeout(function() { toast.classList.remove('show'); }, 3000);
    }
  });
}

// ===== مشاركة عبر واتساب =====
function shareViaWhatsApp() {
  const links = document.querySelectorAll('.store-link-card');
  let text = '🏪 روابط متاجر Ali Ahmed Design:\n\n';
  links.forEach(function(link) {
    text += (link.getAttribute('data-store') || link.href) + '\n';
  });
  text += '\n✨ للتواصل: https://wa.me/201002241591';
  window.open('https://wa.me/?text=' + encodeURIComponent(text), '_blank');
}

// ===== تبديل التبويبات =====
function switchTab(name) {
  var panels = document.querySelectorAll('.tab-panel');
  var tabs = document.querySelectorAll('.nav-links a');
  panels.forEach(function(p) { p.classList.remove('active'); });
  tabs.forEach(function(t) { t.classList.remove('active'); });
  var target = document.querySelector('.tab-panel[data-tab="' + name + '"], #panel-' + name);
  if (target) target.classList.add('active');
  var activeTab = document.querySelector('.nav-links a[onclick*="' + name + '"]');
  if (activeTab) activeTab.classList.add('active');
  window.scrollTo({ top: 0, behavior: 'smooth' });
  // إعادة تشغيل عدادات الإحصائيات عند العودة للرئيسية
  if (name === 'home') {
    setTimeout(function() {
      document.querySelectorAll('.stat-number:not(.counted)').forEach(function(el) {
        var target = parseInt(el.getAttribute('data-target'));
        if (target && !isNaN(target)) {
          el.classList.add('counted');
          var current = 0;
          var inc = Math.ceil(target / 40);
          var timer = setInterval(function() {
            current += inc;
            if (current >= target) { current = target; clearInterval(timer); }
            el.textContent = current;
          }, 30);
        }
      });
    }, 350);
  }
}

// ===== تفعيل التاب النشط حسب الصفحة =====
function initActiveNav() {
  var allTabs = document.querySelectorAll('.nav-links a');
  allTabs.forEach(function(t) { t.classList.remove('active'); });
  if (document.querySelector('.tab-panel')) {
    switchTab('home');
  } else if (window.location.pathname.indexOf('/search') === 0) {
    var blogTab = document.querySelector('.nav-links a[href="/search"]');
    if (blogTab) blogTab.classList.add('active');
  } else {
    var homeTab = document.querySelector('.nav-links a[href="/"]');
    if (homeTab) homeTab.classList.add('active');
  }
}

// ===== التنقل بالسحب (Swipe) للتبويبات =====
function initTabSwipe() {
  var panels = document.querySelector('.tab-panels');
  if (!panels) return;
  var startX = 0, endX = 0;
  var tabs = ['home', 'services', 'about', 'portfolio', 'tools', 'discounts', 'contact'];
  panels.addEventListener('touchstart', function(e) {
    startX = e.changedTouches[0].screenX;
  }, { passive: true });
  panels.addEventListener('touchend', function(e) {
    endX = e.changedTouches[0].screenX;
    var diff = startX - endX;
    if (Math.abs(diff) < 50) return;
    var current = document.querySelector('.tab-panel.active');
    if (!current) return;
    var idx = -1;
    var id = current.id || '';
    var dataTab = current.getAttribute('data-tab') || '';
    var currentName = id.replace('panel-', '') || dataTab;
    tabs.forEach(function(t, i) { if (t === currentName) idx = i; });
    if (idx === -1) return;
    if (diff > 0 && idx < tabs.length - 1) {
      switchTab(tabs[idx + 1]);
    } else if (diff < 0 && idx > 0) {
      switchTab(tabs[idx - 1]);
    }
  }, { passive: true });
}

// ===== دعم روابط التبويبات (هاش لينكس) =====
document.addEventListener('click', function(e) {
  var a = e.target.closest('a[href^="#"]');
  if (!a) return;
  var section = a.getAttribute('href').substring(1);
  var tabMap = { home:'home', services:'services', about:'about', portfolio:'portfolio', tools:'tools', discounts:'discounts', contact:'contact' };
  if (tabMap[section]) {
    e.preventDefault();
    switchTab(tabMap[section]);
  }
});

//

section.script:
//
(function(){
  var container = document.getElementById('heroParticles');
  if (!container) return;
  for (var i = 0; i < 30; i++) {
    var p = document.createElement('div');
    p.className = 'hero-particle';
    p.style.left = Math.random() * 100 + '%';
    p.style.animationDelay = Math.random() * 20 + 's';
    p.style.animationDuration = (15 + Math.random() * 20) + 's';
    p.style.width = (3 + Math.random() * 6) + 'px';
    p.style.height = p.style.width;
    container.appendChild(p);
  }
})();
//
